        code: '// Classement des produits par CA\nRang Produit =\n    RANKX(\n        ALL(Product[name]),\n        [CA Total],\n        ,\n        DESC,\n        Dense\n    )\n\n// CA des Top 5 produits\nCA Top 5 =\n    CALCULATE(\n        [CA Total],\n        TOPN(5,\n            ALL(Product[name]),\n            [CA Total]\n        )\n    )',
