        code: '// CA de la même période l\'an dernier\nCA N-1 =\n    CALCULATE(\n        [CA Total],\n        SAMEPERIODLASTYEAR(DateTable[Date])\n    )\n\n// Taux de croissance annuel (YoY %)\nYoY % =\nVAR Actuel = [CA Total]\nVAR Precedent = [CA N-1]\nRETURN\n    DIVIDE(\n        Actuel - Precedent,\n        Precedent\n    )\n\n// YTD N-1 (cumul année précédente)\nCA YTD N-1 =\n    CALCULATE(\n        [CA YTD],\n        SAMEPERIODLASTYEAR(DateTable[Date])\n    )',
