        code: '// Mois précédent\nCA Mois Prec =\n    CALCULATE(\n        [CA Total],\n        DATEADD(DateTable[Date], -1, MONTH)\n    )\n\n// MoM % (Month-over-Month)\nMoM % =\nVAR Actuel = [CA Total]\nVAR Prec = [CA Mois Prec]\nRETURN DIVIDE(Actuel - Prec, Prec)\n\n// Trimestre précédent\nCA Trim Prec =\n    CALCULATE(\n        [CA Total],\n        DATEADD(DateTable[Date], -1, QUARTER)\n    )\n\n// Moyenne mobile 3 mois avec DATESINPERIOD\nCA 3M =\n    CALCULATE(\n        [CA Total],\n        DATESINPERIOD(\n            DateTable[Date],\n            MAX(DateTable[Date]),\n            -3, MONTH\n        )\n    )',
