  { q: "Ordre pour déployer un rapport en production ?", o: ["Configurer le refresh planifié", "Tester le RLS", "Publier sur le workspace de production", "Assigner les rôles RLS dans le Service"], a: [1, 2, 0, 3], type: "order", d: "DE", ch: 7, w: "Tester d'abord → Publier → Configurer refresh → Assigner RLS (la sécurité en dernier car elle dépend du dataset publié)." }
