var EXERCISES = [
  { id: 1, ch: 1, difficulty: 1, title: "Calcul du CA total", prompt: "Crée une mesure qui calcule le CA total a partir de Sales[SalesAmount].", expectedPattern: /SUM\s*\(\s*Sales\s*\[\s*SalesAmount\s*\]\s*\)/i, altPatterns: [], solution: "CA Total = SUM(Sales[SalesAmount])", hints: ["Utilise SUM", "Colonne Sales[SalesAmount]"], explanation: "SUM additionne toutes les valeurs d'une colonne." },
  { id: 2, ch: 1, difficulty: 1, title: "Compter les lignes", prompt: "Crée une mesure qui compte le nombre total de transactions dans Sales.", expectedPattern: /COUNTROWS\s*\(\s*Sales\s*\)/i, altPatterns: [/COUNTROWS\s*\(\s*'?Sales'?\s*\)/i], solution: "Nb Commandes = COUNTROWS(Sales)", hints: ["Utilise COUNTROWS", "Argument : Sales"], explanation: "COUNTROWS compte le nombre de lignes d'une table." },
  { id: 3, ch: 1, difficulty: 1, title: "Division sécurisée", prompt: "Crée Panier Moyen = DIVIDE([CA Total], [Nb Commandes], 0).", expectedPattern: /DIVIDE\s*\(\s*\[CA Total\]\s*,\s*\[Nb Commandes\]\s*,\s*0\s*\)/i, altPatterns: [/DIVIDE\s*\(\s*\[CA[_ ]Total\]\s*,\s*\[Nb[_ ]Commandes\]\s*,?\s*0?\s*\)/i, /DIVIDE\s*\(.+,.+,\s*0\s*\)/i], solution: "Panier Moyen = DIVIDE([CA Total], [Nb Commandes], 0)", hints: ["Utilise DIVIDE au lieu de /", "3 arguments : num, dénom, défaut"], explanation: "DIVIDE(a, b, alt) retourne alt si b est 0 ou BLANK." },
  { id: 4, ch: 1, difficulty: 1, title: "Compter les valeurs uniques", prompt: "Crée une mesure qui compte les clients uniques via Orders[customerid].", expectedPattern: /DISTINCTCOUNT\s*\(\s*Orders\s*\[\s*customerid\s*\]\s*\)/i, altPatterns: [], solution: "Nb Clients = DISTINCTCOUNT(Orders[customerid])", hints: ["DISTINCTCOUNT = valeurs uniques", "Colonne : Orders[customerid]"], explanation: "DISTINCTCOUNT retourne le nombre de valeurs distinctes." },
  { id: 5, ch: 3, difficulty: 1, title: "Table de dates automatique", prompt: "Crée une table calculée DateTable avec CALENDARAUTO().", expectedPattern: /CALENDARAUTO\s*\(\s*\)/i, altPatterns: [/CALENDAR\s*\(\s*DATE\s*\(.*\)\s*,\s*DATE\s*\(.*\)\s*\)/i], solution: "DateTable = CALENDARAUTO()", hints: ["CALENDARAUTO détecte la plage automatiquement", "Pas de dates à spécifier"], explanation: "CALENDARAUTO() génère une table de dates couvrant le modèle." },
  { id: 6, ch: 3, difficulty: 2, title: "Table de dates avec plage", prompt: "Crée une table avec CALENDAR du 01/01/2019 au 31/12/2023.", expectedPattern: /CALENDAR\s*\(\s*DATE\s*\(\s*2019\s*,\s*1\s*,\s*1\s*\)\s*,\s*DATE\s*\(\s*2023\s*,\s*12\s*,\s*31\s*\)\s*\)/i, altPatterns: [], solution: "DateTable = CALENDAR(DATE(2019,1,1), DATE(2023,12,31))", hints: ["CALENDAR avec DATE pour début et fin", "DATE(année, mois, jour)"], explanation: "CALENDAR(start, end) génère une table de dates continue." },
  { id: 7, ch: 3, difficulty: 2, title: "Colonne calculée RELATED", prompt: "Dans Sales, crée NomProduit = RELATED(Product[name]).", expectedPattern: /RELATED\s*\(\s*Product\s*\[\s*name\s*\]\s*\)/i, altPatterns: [], solution: "NomProduit = RELATED(Product[name])", hints: ["RELATED va chercher côté 1 de la relation", "RELATED(Table[Colonne])"], explanation: "RELATED suit une relation vers la dimension liée." },
  { id: 8, ch: 4, difficulty: 2, title: "CALCULATE filtre simple", prompt: "Crée CA France = CALCULATE([CA Total], Territory[countryregioncode] = \"France\").", expectedPattern: /CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*Territory\s*\[\s*countryregioncode\s*\]\s*=\s*"France"\s*\)/i, altPatterns: [/CALCULATE\s*\(.+,\s*FILTER\s*\(\s*Territory\s*,.+countryregioncode.+France.+\)\s*\)/i], solution: "CA France = CALCULATE([CA Total], Territory[countryregioncode] = \"France\")", hints: ["CALCULATE modifie le contexte de filtre", "2e arg : Table[Col] = \"Val\""], explanation: "CALCULATE évalue dans un contexte modifié." },
  { id: 9, ch: 4, difficulty: 2, title: "CALCULATE avec FILTER", prompt: "Crée CA Premium : [CA Total] pour Product[listprice] > 1000.", expectedPattern: /CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*FILTER\s*\(\s*Product\s*,\s*Product\s*\[\s*listprice\s*\]\s*>\s*1000\s*\)\s*\)/i, altPatterns: [/CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*Product\[listprice\]\s*>\s*1000\s*\)/i], solution: "CA Premium = CALCULATE([CA Total], FILTER(Product, Product[listprice] > 1000))", hints: ["FILTER(table, condition)", "Pour les filtres complexes"], explanation: "FILTER itère et ne garde que les lignes satisfaisant la condition." },
  { id: 10, ch: 4, difficulty: 3, title: "CALCULATE avec KEEPFILTERS", prompt: "Calcule [CA Total] pour France avec KEEPFILTERS (ne pas ecraser le filtre existant).", expectedPattern: /CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*KEEPFILTERS\s*\(\s*Territory\s*\[\s*countryregioncode\s*\]\s*=\s*"?France"?\s*\)\s*\)/i, altPatterns: [/CALCULATE\s*\(.+KEEPFILTERS\s*\(.+countryregioncode.+France.+\)/i], solution: "CA France KF = CALCULATE([CA Total], KEEPFILTERS(Territory[countryregioncode] = \"France\"))", hints: ["KEEPFILTERS ajoute au lieu de remplacer", "Envelopper dans KEEPFILTERS(...)"], explanation: "CALCULATE REMPLACE par défaut. KEEPFILTERS fait INTERSECTION." },
  { id: 11, ch: 4, difficulty: 2, title: "CALCULATE avec ALL", prompt: "Crée CA Global : [CA Total] sans aucun filtre sur Territory.", expectedPattern: /CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*ALL\s*\(\s*Territory\s*\)\s*\)/i, altPatterns: [/CALCULATE\s*\(.+ALL\s*\(\s*Territory\s*\)/i], solution: "CA Global = CALCULATE([CA Total], ALL(Territory))", hints: ["ALL supprime tous les filtres", "ALL(Table)"], explanation: "ALL(Table) supprime tous les filtres actifs." },
  { id: 12, ch: 4, difficulty: 3, title: "CALCULATE avec ALLSELECTED", prompt: "Calcule [CA Total] en gardant les segments mais pas les filtres du visuel. Utilise ALLSELECTED.", expectedPattern: /CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*ALLSELECTED\s*\(\s*Territory\s*\)\s*\)/i, altPatterns: [/CALCULATE\s*\(.+ALLSELECTED\s*\(/i], solution: "CA Visible = CALCULATE([CA Total], ALLSELECTED(Territory))", hints: ["ALLSELECTED garde les segments", "Supprime les filtres d'axe"], explanation: "ALLSELECTED respecte les segments, supprime les filtres d'axe." },
  { id: 13, ch: 4, difficulty: 3, title: "USERELATIONSHIP", prompt: "Crée CA Livraison via la relation inactive Orders[shipdate] / DateTable[Date].", expectedPattern: /CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*USERELATIONSHIP\s*\(\s*Orders\s*\[\s*shipdate\s*\]\s*,\s*DateTable\s*\[\s*Date\s*\]\s*\)\s*\)/i, altPatterns: [/CALCULATE\s*\(.+USERELATIONSHIP\s*\(.+shipdate.+Date.+\)/i], solution: "CA Livraison = CALCULATE([CA Total], USERELATIONSHIP(Orders[shipdate], DateTable[Date]))", hints: ["USERELATIONSHIP active une relation inactive", "Dans CALCULATE"], explanation: "Active temporairement une relation inactive." },
  { id: 14, ch: 5, difficulty: 2, title: "% du total avec ALL", prompt: "Crée % CA Pays = DIVIDE([CA Total], CALCULATE([CA Total], ALL(Territory))).", expectedPattern: /DIVIDE\s*\(\s*\[CA[_ ]Total\]\s*,\s*CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*ALL\s*\(\s*Territory\s*\)\s*\)\s*\)/i, altPatterns: [/DIVIDE\s*\(.+CALCULATE\s*\(.+ALL\s*\(/i], solution: "% CA Pays = DIVIDE([CA Total], CALCULATE([CA Total], ALL(Territory)))", hints: ["Dénominateur : CALCULATE + ALL", "DIVIDE pour protéger"], explanation: "ALL au dénominateur donne le total global." },
  { id: 15, ch: 5, difficulty: 3, title: "Classement RANKX", prompt: "Classe les produits par [CA Total] DESC avec ALL(Product[name]).", expectedPattern: /RANKX\s*\(\s*ALL\s*\(\s*Product\s*\[\s*name\s*\]\s*\)\s*,\s*\[CA[_ ]Total\]/i, altPatterns: [/RANKX\s*\(.+ALL\s*\(.+name.+\).+\[CA/i], solution: "Rang Produit = RANKX(ALL(Product[name]), [CA Total], , DESC)", hints: ["RANKX(table, expression, , ordre)", "ALL pour tous les produits"], explanation: "RANKX itère et crée un rang. ALL pour le classement complet." },
  { id: 16, ch: 5, difficulty: 2, title: "Iteration SUMX", prompt: "Crée CA Calculé = SUMX(Sales, Sales[orderqty] * Sales[unitprice]).", expectedPattern: /SUMX\s*\(\s*Sales\s*,\s*Sales\s*\[\s*orderqty\s*\]\s*\*\s*Sales\s*\[\s*unitprice\s*\]\s*\)/i, altPatterns: [/SUMX\s*\(\s*'?Sales'?\s*,.+orderqty.+\*.+unitprice/i, /SUMX\s*\(\s*'?Sales'?\s*,.+unitprice.+\*.+orderqty/i], solution: "CA Calcule = SUMX(Sales, Sales[orderqty] * Sales[unitprice])", hints: ["SUMX itère ligne par ligne", "SUMX(table, expression)"], explanation: "SUMX parcourt chaque ligne et fait la somme des expressions. Idéal pour les calculs multi-colonnes." },
  { id: 17, ch: 5, difficulty: 2, title: "Pattern VAR / RETURN", prompt: "Crée Marge avec VAR vCA = [CA Total], VAR vCout = [Cout Total], RETURN vCA - vCout.", expectedPattern: /VAR\s+\w+\s*=\s*\[CA[_ ]Total\][\s\S]*VAR\s+\w+\s*=\s*\[Cout[_ ]Total\][\s\S]*RETURN/i, altPatterns: [/VAR[\s\S]+RETURN[\s\S]+\-/i], solution: "Marge =\nVAR vCA = [CA Total]\nVAR vCout = [Cout Total]\nRETURN vCA - vCout", hints: ["VAR stocke, RETURN utilise", "VAR nom = expression"], explanation: "VAR/RETURN améliore lisibilité et performances." },
  { id: 18, ch: 5, difficulty: 2, title: "SWITCH(TRUE())", prompt: "Crée Segment : VIP si [CA Total] > 10000, Standard si > 1000, sinon Petit.", expectedPattern: /SWITCH\s*\(\s*TRUE\s*\(\s*\)\s*,\s*\[CA[_ ]Total\]\s*>\s*10000\s*,\s*"VIP"/i, altPatterns: [/SWITCH\s*\(\s*TRUE\s*\(\s*\)/i], solution: "Segment = SWITCH(TRUE(), [CA Total] > 10000, \"VIP\", [CA Total] > 1000, \"Standard\", \"Petit\")", hints: ["SWITCH(TRUE(), ...) évalue dans l'ordre", "Comme IF/ELSE IF"], explanation: "SWITCH(TRUE(), ...) est plus lisible que des IF imbriqués." },
  { id: 19, ch: 5, difficulty: 2, title: "IF + ISBLANK", prompt: "Crée CA Affiché : \"Aucune donnée\" si [CA Total] est BLANK, sinon [CA Total].", expectedPattern: /IF\s*\(\s*ISBLANK\s*\(\s*\[CA[_ ]Total\]\s*\)\s*,\s*"Aucune donn/i, altPatterns: [/IF\s*\(\s*ISBLANK\s*\(.+\)\s*,/i], solution: "CA Affiché = IF(ISBLANK([CA Total]), \"Aucune donnée\", [CA Total])", hints: ["ISBLANK teste si BLANK", "IF(cond, vrai, faux)"], explanation: "ISBLANK teste si une expression retourne BLANK." },
  { id: 20, ch: 6, difficulty: 2, title: "Cumul annuel TOTALYTD", prompt: "Crée CA YTD = TOTALYTD([CA Total], DateTable[Date]).", expectedPattern: /TOTALYTD\s*\(\s*\[CA[_ ]Total\]\s*,\s*DateTable\s*\[\s*Date\s*\]\s*\)/i, altPatterns: [/CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*DATESYTD\s*\(\s*DateTable\s*\[\s*Date\s*\]\s*\)\s*\)/i], solution: "CA YTD = TOTALYTD([CA Total], DateTable[Date])", hints: ["TOTALYTD cumule depuis le 1er janvier", "Passe DateTable[Date]"], explanation: "TOTALYTD accumule depuis le début de l'année." },
  { id: 21, ch: 6, difficulty: 2, title: "Même période N-1", prompt: "Crée CA N-1 = CALCULATE([CA Total], SAMEPERIODLASTYEAR(DateTable[Date])).", expectedPattern: /CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*SAMEPERIODLASTYEAR\s*\(\s*DateTable\s*\[\s*Date\s*\]\s*\)\s*\)/i, altPatterns: [/CALCULATE\s*\(.+SAMEPERIODLASTYEAR\s*\(/i], solution: "CA N-1 = CALCULATE([CA Total], SAMEPERIODLASTYEAR(DateTable[Date]))", hints: ["SAMEPERIODLASTYEAR décale d'un an", "Dans CALCULATE"], explanation: "Raccourci pour DATEADD(..., -1, YEAR)." },
  { id: 22, ch: 6, difficulty: 3, title: "Variation YoY%", prompt: "Crée YoY% = DIVIDE([CA Total] - [CA N-1], [CA N-1]).", expectedPattern: /DIVIDE\s*\(\s*\[CA[_ ]Total\]\s*-\s*\[CA[_ ]N-1\]\s*,\s*\[CA[_ ]N-1\]\s*\)/i, altPatterns: [/DIVIDE\s*\(.+\-.+\[CA.N.1\].+\[CA.N.1\]/i], solution: "YoY% = DIVIDE([CA Total] - [CA N-1], [CA N-1])", hints: ["(actuel - ancien) / ancien", "DIVIDE protege contre /0"], explanation: "DIVIDE protège quand CA N-1 est 0 ou BLANK." },
  { id: 23, ch: 6, difficulty: 2, title: "Décalage DATEADD", prompt: "Crée CA Mois Précédent = CALCULATE([CA Total], DATEADD(DateTable[Date], -1, MONTH)).", expectedPattern: /CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*DATEADD\s*\(\s*DateTable\s*\[\s*Date\s*\]\s*,\s*-1\s*,\s*MONTH\s*\)\s*\)/i, altPatterns: [/CALCULATE\s*\(.+DATEADD\s*\(.+-1.+MONTH/i], solution: "CA Mois Précédent = CALCULATE([CA Total], DATEADD(DateTable[Date], -1, MONTH))", hints: ["DATEADD(col, décalage, unité)", "-1, MONTH"], explanation: "DATEADD accepte DAY, MONTH, QUARTER, YEAR." },
  { id: 24, ch: 6, difficulty: 2, title: "Cumul TOTALQTD", prompt: "Crée CA QTD = TOTALQTD([CA Total], DateTable[Date]).", expectedPattern: /TOTALQTD\s*\(\s*\[CA[_ ]Total\]\s*,\s*DateTable\s*\[\s*Date\s*\]\s*\)/i, altPatterns: [/CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*DATESQTD\s*\(\s*DateTable\s*\[\s*Date\s*\]\s*\)\s*\)/i], solution: "CA QTD = TOTALQTD([CA Total], DateTable[Date])", hints: ["Comme TOTALYTD pour le trimestre", "Même syntaxe"], explanation: "TOTALQTD accumule depuis le début du trimestre." },
  { id: 25, ch: 6, difficulty: 3, title: "Variation MoM%", prompt: "Crée MoM% avec VAR pour le mois précédent (DATEADD) puis DIVIDE.", expectedPattern: /VAR[\s\S]*DATEADD\s*\(\s*DateTable\s*\[\s*Date\s*\]\s*,\s*-1\s*,\s*MONTH\s*\)[\s\S]*RETURN[\s\S]*DIVIDE/i, altPatterns: [/DIVIDE\s*\(.+CALCULATE\s*\(.+DATEADD.+MONTH/i], solution: "MoM% =\nVAR vPrev = CALCULATE([CA Total], DATEADD(DateTable[Date], -1, MONTH))\nRETURN DIVIDE([CA Total] - vPrev, vPrev)", hints: ["VAR pour stocker le mois précédent", "VAR/RETURN + DIVIDE"], explanation: "VAR + DATEADD + DIVIDE = pattern standard pour variations." },
  { id: 26, ch: 5, difficulty: 3, title: "AVERAGEX + VALUES", prompt: "Crée CA moyen par client = AVERAGEX(VALUES(Orders[customerid]), [CA Total]).", expectedPattern: /AVERAGEX\s*\(\s*VALUES\s*\(\s*Orders\s*\[\s*customerid\s*\]\s*\)\s*,\s*\[CA[_ ]Total\]\s*\)/i, altPatterns: [/AVERAGEX\s*\(.+VALUES\s*\(.+customerid.+\).+\[CA/i], solution: "CA Moyen Client = AVERAGEX(VALUES(Orders[customerid]), [CA Total])", hints: ["AVERAGEX itere et fait la moyenne", "VALUES = valeurs distinctes"], explanation: "AVERAGEX itère sur chaque client unique." },
  { id: 27, ch: 4, difficulty: 3, title: "REMOVEFILTERS", prompt: "Calcule [CA Total] en supprimant uniquement le filtre sur Product[productsubcategoryid].", expectedPattern: /CALCULATE\s*\(\s*\[CA[_ ]Total\]\s*,\s*REMOVEFILTERS\s*\(\s*Product\s*\[\s*productsubcategoryid\s*\]\s*\)\s*\)/i, altPatterns: [/CALCULATE\s*\(.+ALL\s*\(\s*Product\s*\[\s*productsubcategoryid\s*\]\s*\)/i], solution: "CA Sans Filtre Cat = CALCULATE([CA Total], REMOVEFILTERS(Product[productsubcategoryid]))", hints: ["REMOVEFILTERS = alias de ALL", "Passe une colonne"], explanation: "REMOVEFILTERS(colonne) supprime le filtre sur cette colonne." },
  { id: 28, ch: 5, difficulty: 3, title: "SELECTEDVALUE", prompt: "Crée Pays Sélectionné : valeur de Territory[countryregioncode] ou \"Tous\" si multi-sélection.", expectedPattern: /SELECTEDVALUE\s*\(\s*Territory\s*\[\s*countryregioncode\s*\]\s*,\s*"Tous"\s*\)/i, altPatterns: [/SELECTEDVALUE\s*\(.+countryregioncode.+Tous/i], solution: "Pays Selectionne = SELECTEDVALUE(Territory[countryregioncode], \"Tous\")", hints: ["SELECTEDVALUE = valeur si 1 filtre", "2e arg = défaut"], explanation: "Retourne la valeur unique du contexte ou la valeur par défaut." }
];

// ═══════════════════════════════════════════════════════════
// RACING GAMES — Missions projet parallèle
// ═══════════════════════════════════════════════════════════
var RACING_MISSIONS = [
  // Ch.1 — Connexion et exploration (4 missions)
  { id: "r1", ch: 1, title: "Connecter racing_prices", text: "Connecte la base PostgreSQL racing_prices (localhost:5432, postgres/postgres) dans Power BI. Mode Import. Vérifie que les 4 tables apparaissent : games, price_history, game_sales, shops.", type: "action", xp: 15, solution: "Accueil → Obtenir les données → Base de données PostgreSQL → Serveur : localhost, Base : racing_prices → Mode Import → Authentification : postgres/postgres → Sélectionner les 4 tables → Transformer les données pour vérifier.\n\nRésultat : 4 tables dans le navigateur. games = catalogue des jeux, price_history = historique des prix, game_sales = ventes mensuelles, shops = détails des boutiques.", why: "Même workflow que AdventureWorks. La base racing_prices est ton projet personnel — tu la connais par coeur, c'est un avantage en entretien." },
  { id: "r2", ch: 1, title: "Explorer les tables", text: "En vue Données, explore les 4 tables. Note le nombre de lignes, les colonnes clés et les types de chaque table.", type: "action", xp: 15, solution: "games : colonnes game_id (PK), title, publisher, developer, genre, release_date, platform. price_history : colonnes id, game_id (FK), shop_id (FK), price_eur, date_checked. game_sales : colonnes id, game_id (FK), month, units_sold, revenue_eur. shops : colonnes shop_id (PK), name, url, country.\n\nVérifie les types : price_eur et revenue_eur doivent être en Décimal, release_date et date_checked en Date, units_sold en Entier.", why: "Explorer les données avant de modéliser est la première étape. Tu dois comprendre la granularité de chaque table." },
  { id: "r3", ch: 1, title: "Nb Jeux et Nb Prix", text: "Crée 2 mesures de base : Nb Jeux = DISTINCTCOUNT(games[game_id]) et Nb Prix = COUNTROWS(price_history). Affiche-les en Cartes.", type: "dax", expectedPattern: /DISTINCTCOUNT\s*\(\s*games\s*\[\s*game_id\s*\]\s*\)/i, altPatterns: [/COUNTROWS\s*\(\s*games\s*\)/i], solution: "Nb Jeux = DISTINCTCOUNT(games[game_id])\nNb Prix = COUNTROWS(price_history)\n\nDISTINCTCOUNT sur game_id car un même jeu peut apparaître dans plusieurs tables. COUNTROWS sur price_history car chaque ligne = une observation de prix unique.", hints: ["DISTINCTCOUNT pour les valeurs uniques", "COUNTROWS pour le nombre total d'observations"], xp: 30 },
  { id: "r4", ch: 1, title: "Prix Moyen Global", text: "Crée Prix Moyen = AVERAGE(price_history[price_eur]). Carte formatée en euros.", type: "dax", expectedPattern: /AVERAGE\s*\(\s*price_history\s*\[\s*price_eur\s*\]\s*\)/i, altPatterns: [/AVERAGEX\s*\(\s*price_history\s*,\s*price_history\s*\[\s*price_eur\s*\]\s*\)/i], solution: "Prix Moyen = AVERAGE(price_history[price_eur])\n\nAVERAGE calcule la moyenne de toutes les observations de prix. Formate en € avec 2 décimales via Outils de mesure → Format → Devise.", hints: ["AVERAGE pour la moyenne simple", "Formate en € via Outils de mesure"], xp: 30 },

  // Ch.2 — Nettoyage Power Query (5 missions)
  { id: "r5", ch: 2, title: "Vérifier et corriger les types", text: "Dans PQ, vérifie les types de chaque table. Corrige : price_eur en Décimal, release_date en Date, units_sold en Entier. Renomme les tables en PascalCase (Games, PriceHistory, GameSales, Shops).", type: "action", xp: 15, solution: "Ouvrir PQ → pour chaque table :\n1. Vérifier les types (icône en haut de chaque colonne)\n2. price_eur : Décimal fixe\n3. release_date, date_checked : Date\n4. units_sold : Entier\n5. Renommer : games → Games, price_history → PriceHistory, game_sales → GameSales, shops → Shops\n\nLes types sont probablement déjà corrects (PostgreSQL), mais toujours vérifier.", why: "Types = étape n°1. Renommer en PascalCase rend le modèle lisible." },
  { id: "r6", ch: 2, title: "Filtrer les prix invalides", text: "Dans PQ, filtre PriceHistory pour garder uniquement price_eur > 0. Combien de lignes restent ?", type: "action", xp: 15, solution: "Cliquer sur la flèche de price_eur → Filtres numériques → Supérieur à → 0.\n\nLes prix à 0 sont des jeux gratuits temporaires ou des erreurs de scraping. Les exclure donne des moyennes de prix plus réalistes.\n\nVérifie le nombre de lignes avant/après dans la barre d'état en bas.", why: "Filtrer les données invalides en amont (PQ) allège le modèle et évite de fausser les analyses." },
  { id: "r7", ch: 2, title: "Colonne MonthsSinceLaunch", text: "Dans PQ, crée une colonne calculée MonthsSinceLaunch dans PriceHistory : nombre de mois entre release_date (via Merge avec Games) et date_checked.", type: "action", xp: 20, solution: "Étape 1 : Merge PriceHistory avec Games sur game_id (Left Outer Join).\nÉtape 2 : Expand la colonne Games pour récupérer release_date.\nÉtape 3 : Ajouter colonne → Colonne personnalisée :\n= Duration.TotalDays([date_checked] - [release_date]) / 30\nÉtape 4 : Arrondir à l'entier (Type → Entier).\nÉtape 5 : Renommer en MonthsSinceLaunch.\n\nCette colonne est essentielle pour l'analyse de dépréciation : comment le prix évolue-t-il dans le temps après la sortie.", why: "MonthsSinceLaunch est la variable clé du projet Racing Games : elle permet de tracer la courbe de dépréciation." },
  { id: "r8", ch: 2, title: "Colonne PriceRange", text: "Crée une colonne conditionnelle PriceRange dans PriceHistory : Premium (>40€), Standard (15-40€), Budget (<15€).", type: "action", xp: 15, solution: "Ajouter colonne → Colonne conditionnelle → Nom : PriceRange\nSi price_eur > 40 alors \"Premium\"\nSinon si price_eur >= 15 alors \"Standard\"\nSinon \"Budget\"\n\nEn M : = if [price_eur] > 40 then \"Premium\" else if [price_eur] >= 15 then \"Standard\" else \"Budget\"\n\nSegmentation fixe par observation de prix, pas dynamique → PQ est le bon endroit.", why: "La segmentation par prix permet d'analyser les comportements de dépréciation par gamme." },
  { id: "r9", ch: 2, title: "Supprimer colonnes inutiles", text: "Dans chaque table, supprime les colonnes inutiles. Garde uniquement les colonnes nécessaires à l'analyse.", type: "action", xp: 15, solution: "Games : garder game_id, title, publisher, developer, genre, release_date, platform.\nPriceHistory : garder id, game_id, shop_id, price_eur, date_checked, MonthsSinceLaunch, PriceRange.\nGameSales : garder id, game_id, month, units_sold, revenue_eur.\nShops : garder shop_id, name, country.\n\nSupprimer les colonnes techniques (URLs, timestamps de scraping, etc.) qui alourdissent le modèle.", why: "Moins de colonnes = modèle plus rapide. Ne garder que ce qui sert à l'analyse." },

  // Ch.3 — Modélisation (4 missions)
  { id: "r10", ch: 3, title: "Créer les relations", text: "Crée les 3 relations : Games → PriceHistory (game_id), Games → GameSales (game_id), Shops → PriceHistory (shop_id). Toutes en 1:N Single.", type: "action", xp: 20, solution: "En vue Modèle :\n1. Games[game_id] (1) → PriceHistory[game_id] (N) — Single\n2. Games[game_id] (1) → GameSales[game_id] (N) — Single\n3. Shops[shop_id] (1) → PriceHistory[shop_id] (N) — Single\n\nVérifier que Games et Shops sont du côté 1 (valeurs uniques). Si N:N détecté, nettoyer les doublons dans PQ.", why: "Le schéma est une étoile avec 2 tables de faits (PriceHistory et GameSales) partageant la dimension Games. C'est un schéma constellation." },
  { id: "r11", ch: 3, title: "Table de dates Racing", text: "Crée une DateTable pour le projet Racing avec CALENDAR(DATE(2020,1,1), DATE(2026,12,31)). Ajoute Année, Mois, NomMois, Trimestre. Marque-la et relie-la à PriceHistory[date_checked].", type: "dax", expectedPattern: /CALENDAR\s*\(\s*DATE\s*\(\s*2020/i, altPatterns: [/CALENDARAUTO/i], solution: "RacingDateTable = ADDCOLUMNS(\n    CALENDAR(DATE(2020,1,1), DATE(2026,12,31)),\n    \"Année\", YEAR([Date]),\n    \"Mois\", MONTH([Date]),\n    \"NomMois\", FORMAT([Date], \"MMMM\"),\n    \"Trimestre\", \"Q\" & FORMAT([Date], \"Q\")\n)\n\nClic droit → Marquer comme table de dates → Date.\nRelation : RacingDateTable[Date] (1) → PriceHistory[date_checked] (N).", hints: ["CALENDAR avec bornes explicites", "N'oublie pas de marquer la table"], xp: 30 },
  { id: "r12", ch: 3, title: "Vérifier le schéma étoile", text: "Organise visuellement le modèle en étoile. Games au centre (dimension partagée), PriceHistory et GameSales comme faits, Shops et DateTable en périphérie.", type: "action", xp: 15, solution: "Disposition recommandée :\n- Games au centre (dimension partagée entre les 2 tables de faits)\n- PriceHistory en haut-gauche\n- GameSales en haut-droite\n- Shops à gauche (liée à PriceHistory)\n- RacingDateTable à droite (liée à PriceHistory)\n\nC'est un schéma constellation (2 tables de faits partageant une dimension). Vérifie que toutes les relations sont en trait plein (actives) et en Single (→).", why: "Un modèle bien organisé est plus facile à maintenir et à présenter en entretien." },
  { id: "r13", ch: 3, title: "Masquer les colonnes techniques", text: "Masque les colonnes id, game_id, shop_id dans les tables de faits. Elles servent aux relations mais pas aux visuels.", type: "action", xp: 10, solution: "Clic droit sur chaque colonne technique (id, game_id, shop_id dans PriceHistory et GameSales) → Masquer dans la vue rapport.\n\nLes colonnes restent disponibles pour les relations et le DAX, mais n'apparaissent plus dans le panneau Champs pour les créateurs de visuels.", why: "Masquer les colonnes techniques nettoie l'interface et guide les utilisateurs vers les bonnes colonnes." },

  // Ch.4 — CALCULATE prix par contexte (5 missions)
  { id: "r14", ch: 4, title: "Prix Moyen par Publisher", text: "Crée une mesure qui calcule le prix moyen par éditeur en utilisant CALCULATE + AVERAGE.", type: "dax", expectedPattern: /AVERAGE\s*\(\s*PriceHistory\s*\[\s*price_eur\s*\]\s*\)/i, altPatterns: [/CALCULATE\s*\(\s*AVERAGE/i], solution: "Prix Moyen = AVERAGE(PriceHistory[price_eur])\n\nPas besoin de CALCULATE ici : dans un visuel avec Games[publisher] en axe, le contexte de filtre filtre automatiquement par éditeur. La mesure AVERAGE se recalcule pour chaque publisher.\n\nPour forcer un éditeur spécifique :\nPrix Moyen Ubisoft = CALCULATE(AVERAGE(PriceHistory[price_eur]), Games[publisher] = \"Ubisoft\")", hints: ["AVERAGE se recalcule selon le contexte", "CALCULATE pour forcer un éditeur"], xp: 30 },
  { id: "r15", ch: 4, title: "Prix Moyen par Boutique", text: "Crée un tableau croisé Boutique × Prix Moyen. Ajoute une mesure CALCULATE pour le prix moyen global (toutes boutiques).", type: "dax", expectedPattern: /CALCULATE\s*\(\s*\[Prix Moyen\]\s*,\s*ALL\s*\(\s*Shops\s*\)\s*\)/i, altPatterns: [/CALCULATE\s*\(.+ALL\s*\(\s*Shops/i], solution: "Prix Moyen Global = CALCULATE([Prix Moyen], ALL(Shops))\n\nDans un tableau avec Shops[name] en lignes :\n- [Prix Moyen] se recalcule par boutique (contexte de filtre)\n- [Prix Moyen Global] ignore la boutique (ALL supprime le filtre)\n\nAjoute % Écart = DIVIDE([Prix Moyen] - [Prix Moyen Global], [Prix Moyen Global]) pour voir quelles boutiques sont plus chères que la moyenne.", hints: ["ALL(Shops) supprime le filtre boutique", "DIVIDE pour calculer l'écart en %"], xp: 30 },
  { id: "r16", ch: 4, title: "CA Ubisoft uniquement", text: "Crée CA Ubisoft = CALCULATE(SUM(GameSales[revenue_eur]), Games[publisher] = \"Ubisoft\"). Compare avec le CA total.", type: "dax", expectedPattern: /CALCULATE\s*\(\s*SUM\s*\(\s*GameSales\s*\[\s*revenue_eur\s*\]\s*\)\s*,\s*Games\s*\[\s*publisher\s*\]\s*=\s*"Ubisoft"\s*\)/i, altPatterns: [/CALCULATE\s*\(.+publisher.+Ubisoft/i], solution: "CA Total Racing = SUM(GameSales[revenue_eur])\nCA Ubisoft = CALCULATE([CA Total Racing], Games[publisher] = \"Ubisoft\")\n% Ubisoft = DIVIDE([CA Ubisoft], [CA Total Racing])\n\nCe trio de mesures montre la part de marché d'Ubisoft dans les jeux de course. Affiche en Carte : CA Ubisoft + % Ubisoft.", hints: ["CALCULATE force le filtre sur publisher", "DIVIDE pour le pourcentage"], xp: 30 },
  { id: "r17", ch: 4, title: "Prix par plateforme avec FILTER", text: "Crée le prix moyen des jeux dont le prix initial (au lancement) était supérieur à 50€. Utilise FILTER.", type: "dax", expectedPattern: /FILTER\s*\(\s*PriceHistory/i, altPatterns: [/CALCULATE\s*\(.+FILTER/i], solution: "Prix Moyen Premium Launch =\n    CALCULATE(\n        AVERAGE(PriceHistory[price_eur]),\n        FILTER(\n            PriceHistory,\n            PriceHistory[MonthsSinceLaunch] <= 1\n                && PriceHistory[price_eur] > 50\n        )\n    )\n\nFILTER est nécessaire car on combine 2 conditions sur des colonnes différentes avec une expression complexe (&&). Un filtre direct CALCULATE n'accepte qu'une condition simple par colonne.", hints: ["FILTER pour les conditions complexes", "MonthsSinceLaunch <= 1 = prix au lancement"], xp: 30 },
  { id: "r18", ch: 4, title: "Nb jeux par genre avec CALCULATE", text: "Crée un Histogramme montrant le nombre de jeux par genre. Ajoute une mesure % du total avec ALL(Games).", type: "dax", expectedPattern: /ALL\s*\(\s*Games\s*\)/i, altPatterns: [/CALCULATE\s*\(.+ALL/i], solution: "Nb Jeux = DISTINCTCOUNT(Games[game_id])\n% Jeux Genre = DIVIDE(\n    [Nb Jeux],\n    CALCULATE([Nb Jeux], ALL(Games))\n)\n\nDans un Histogramme avec Games[genre] en axe :\n- [Nb Jeux] compte les jeux du genre (contexte)\n- Le dénominateur avec ALL(Games) donne le total tous genres\n- % Jeux Genre montre la part de chaque genre", hints: ["ALL(Games) pour le total global", "DIVIDE pour le pourcentage"], xp: 30 },

  // Ch.5 — Classements et analyse avancée (5 missions)
  { id: "r19", ch: 5, title: "Top jeux par prix moyen", text: "Classe les jeux par prix moyen décroissant avec RANKX. Affiche le Top 10.", type: "dax", expectedPattern: /RANKX\s*\(\s*ALL\s*\(\s*Games\s*\[\s*title\s*\]\s*\)/i, altPatterns: [/RANKX\s*\(.+ALL\s*\(.+title/i], solution: "Rang Prix = RANKX(\n    ALL(Games[title]),\n    [Prix Moyen],\n    ,\n    DESC,\n    Dense\n)\n\nALL(Games[title]) est OBLIGATOIRE sinon rang = 1 partout. Dense = pas de trous dans le classement.\n\nPour le Top 10, utilise un filtre visuel (Top N) ou :\nCA Top 10 = CALCULATE([Prix Moyen], TOPN(10, ALL(Games[title]), [Prix Moyen]))", hints: ["ALL obligatoire dans RANKX", "Dense pour un classement sans trous"], xp: 30 },
  { id: "r20", ch: 5, title: "Dépréciation en %", text: "Crée une mesure de dépréciation : % de baisse du prix actuel par rapport au prix de lancement.", type: "dax", expectedPattern: /DIVIDE/i, altPatterns: [/VAR.+RETURN/i], solution: "Depreciation % =\nVAR PrixActuel = [Prix Moyen]\nVAR PrixLancement = CALCULATE(\n    AVERAGE(PriceHistory[price_eur]),\n    FILTER(PriceHistory, PriceHistory[MonthsSinceLaunch] <= 1)\n)\nRETURN\n    DIVIDE(PrixLancement - PrixActuel, PrixLancement)\n\nRésultat : 0% = pas de baisse, 50% = prix divisé par 2, 80% = prix à 20% du prix de lancement.\n\nFormate en % via Outils de mesure.", hints: ["VAR pour stocker prix lancement et actuel", "DIVIDE pour le pourcentage de baisse"], xp: 30 },
  { id: "r21", ch: 5, title: "SUMX revenus pondérés", text: "Crée Revenu Pondéré = SUMX(GameSales, GameSales[units_sold] * GameSales[revenue_eur] / total_units). Calcul avancé multi-colonnes.", type: "dax", expectedPattern: /SUMX\s*\(\s*GameSales/i, altPatterns: [/SUMX/i], solution: "Revenu Par Unité =\n    DIVIDE(\n        SUM(GameSales[revenue_eur]),\n        SUM(GameSales[units_sold]),\n        0\n    )\n\nOu version SUMX pour un calcul par ligne :\nRevenu Calculé = SUMX(\n    GameSales,\n    GameSales[units_sold] * RELATED(Games[base_price])\n)\n\nSUMX parcourt chaque ligne de GameSales et multiplie les colonnes. SUM ne peut agréger qu'une seule colonne.", hints: ["SUMX pour les calculs multi-colonnes", "RELATED pour accéder aux dimensions"], xp: 30 },
  { id: "r22", ch: 5, title: "Segmentation SWITCH", text: "Crée Segment Prix = SWITCH(TRUE(), prix > 50 → AAA, prix > 25 → Standard, prix > 10 → Indie, sinon → Budget).", type: "dax", expectedPattern: /SWITCH\s*\(\s*TRUE\s*\(\s*\)/i, altPatterns: [/SWITCH/i], solution: "Segment Prix =\nVAR px = [Prix Moyen]\nRETURN SWITCH(TRUE(),\n    px > 50, \"AAA\",\n    px > 25, \"Standard\",\n    px > 10, \"Indie\",\n    \"Budget\"\n)\n\nOrdre restrictif d'abord : >50 avant >25 avant >10. Si tu mets >10 en premier, un jeu à 60€ serait classé Indie.", hints: ["SWITCH(TRUE(), ...) avec ordre restrictif", "VAR pour stocker le prix avant SWITCH"], xp: 30 },
  { id: "r23", ch: 5, title: "Months to 50%", text: "Calcule le nombre moyen de mois pour qu'un jeu perde 50% de son prix de lancement. Utilise AVERAGEX + FILTER.", type: "dax", expectedPattern: /AVERAGEX/i, altPatterns: [/FILTER.+MonthsSinceLaunch/i], solution: "Months To Half Price =\n    AVERAGEX(\n        VALUES(Games[game_id]),\n        CALCULATE(\n            MIN(PriceHistory[MonthsSinceLaunch]),\n            FILTER(\n                PriceHistory,\n                PriceHistory[price_eur] <= CALCULATE(MAX(PriceHistory[price_eur]), PriceHistory[MonthsSinceLaunch] <= 1) * 0.5\n            )\n        )\n    )\n\nCette mesure itère sur chaque jeu, trouve le premier mois où le prix passe sous 50% du prix de lancement, puis fait la moyenne. C'est un KPI business clé : combien de temps avant qu'un jeu perde la moitié de sa valeur.", hints: ["AVERAGEX itère sur chaque jeu", "FILTER trouve le premier mois sous 50%"], xp: 40 },

  // Ch.6 — Time Intelligence dépréciation (5 missions)
  { id: "r24", ch: 6, title: "Prix Moyen YTD Racing", text: "Crée Prix Moyen YTD = TOTALYTD(AVERAGE(PriceHistory[price_eur]), RacingDateTable[Date]).", type: "dax", expectedPattern: /TOTALYTD/i, altPatterns: [/DATESYTD/i], solution: "Prix Moyen YTD =\n    CALCULATE(\n        AVERAGE(PriceHistory[price_eur]),\n        DATESYTD(RacingDateTable[Date])\n    )\n\nOu raccourci : TOTALYTD(AVERAGE(PriceHistory[price_eur]), RacingDateTable[Date])\n\nMême pattern que CA YTD mais avec AVERAGE au lieu de SUM. Le YTD montre l'évolution du prix moyen depuis le début de l'année.", hints: ["Même pattern que CA YTD", "AVERAGE au lieu de SUM"], xp: 30 },
  { id: "r25", ch: 6, title: "Prix N-1 Racing", text: "Crée Prix N-1 = CALCULATE([Prix Moyen], SAMEPERIODLASTYEAR(RacingDateTable[Date])). Compare avec le prix actuel.", type: "dax", expectedPattern: /SAMEPERIODLASTYEAR/i, altPatterns: [/DATEADD\s*\(.+-1.+YEAR/i], solution: "Prix N-1 =\n    CALCULATE(\n        [Prix Moyen],\n        SAMEPERIODLASTYEAR(RacingDateTable[Date])\n    )\n\nVariation Prix YoY =\nVAR Actuel = [Prix Moyen]\nVAR Precedent = [Prix N-1]\nRETURN DIVIDE(Actuel - Precedent, Precedent)\n\nUne variation négative (ex: -15%) signifie que les prix baissent d'une année sur l'autre. C'est la tendance de dépréciation globale du marché.", hints: ["SAMEPERIODLASTYEAR décale d'un an", "Variation négative = baisse des prix"], xp: 30 },
  { id: "r26", ch: 6, title: "Courbe de dépréciation", text: "Crée un Graphique en courbes : axe = MonthsSinceLaunch, valeur = Prix Moyen. Cette courbe montre comment le prix baisse au fil du temps après la sortie.", type: "action", xp: 20, solution: "Graphique en courbes :\n- Axe X = PriceHistory[MonthsSinceLaunch]\n- Valeur = [Prix Moyen]\n\nLa courbe devrait montrer une baisse rapide les 6 premiers mois, puis un plateau. C'est la courbe de dépréciation caractéristique des jeux vidéo.\n\nAjoute un segment Games[publisher] pour comparer les courbes par éditeur. Ubisoft déprecie-t-il plus vite que les autres ?\n\nAstuce : filtre MonthsSinceLaunch entre 0 et 36 pour éviter le bruit des très vieilles données.", why: "Cette courbe est LE livrable clé du projet Racing Games. Elle montre visuellement comment les prix évoluent après le lancement." },
  { id: "r27", ch: 6, title: "DATEADD prix mensuel", text: "Crée Prix M-1 = CALCULATE([Prix Moyen], DATEADD(RacingDateTable[Date], -1, MONTH)). Calcule le MoM % du prix.", type: "dax", expectedPattern: /DATEADD\s*\(.+-1.+MONTH/i, altPatterns: [/CALCULATE\s*\(.+DATEADD/i], solution: "Prix M-1 =\n    CALCULATE(\n        [Prix Moyen],\n        DATEADD(RacingDateTable[Date], -1, MONTH)\n    )\n\nPrix MoM % =\nVAR Actuel = [Prix Moyen]\nVAR Prec = [Prix M-1]\nRETURN DIVIDE(Actuel - Prec, Prec)\n\nUn MoM négatif constant signifie que les prix baissent chaque mois. C'est la vitesse de dépréciation.", hints: ["DATEADD(-1, MONTH) pour le mois précédent", "MoM négatif = baisse mensuelle des prix"], xp: 30 },
  { id: "r28", ch: 6, title: "Comparaison YoY par éditeur", text: "Crée un tableau croisé : Publisher × Année × Prix Moyen × Prix N-1 × YoY %. Quel éditeur déprecie le plus vite ?", type: "action", xp: 20, solution: "Matrice :\n- Lignes = Games[publisher]\n- Colonnes = RacingDateTable[Année]\n- Valeurs = [Prix Moyen], [Prix N-1], [Variation Prix YoY]\n\nMFC sur Variation Prix YoY : vert si > 0 (prix en hausse — rare), rouge si < 0 (dépréciation).\n\nAnalyse business : les éditeurs avec les plus grosses dépréciations YoY sont ceux qui font les plus grosses promotions ou dont les jeux perdent le plus vite en valeur perçue.", why: "Ce tableau est un livrable clé pour un entretien : il montre ta capacité à croiser Time Intelligence + dimensions business." },

  // Ch.7 — Construction du dashboard Racing (6 missions)
  { id: "r29", ch: 7, title: "KPI Cartes Racing", text: "Crée 4 Cartes KPI : Nb Jeux, Prix Moyen actuel, Dépréciation Moyenne %, Months to Half Price.", type: "action", xp: 15, solution: "4 Cartes en haut de la page :\n1. Nb Jeux = DISTINCTCOUNT(Games[game_id]) → ex: 150\n2. Prix Moyen = AVERAGE(PriceHistory[price_eur]) → ex: 24.50€\n3. Dépréciation Moy = mesure Depreciation % → ex: -42%\n4. Months to Half = mesure Months To Half Price → ex: 8 mois\n\nFormatage : Nb Jeux en entier, Prix en €, Dépréciation en %, Months en entier + 'mois'.\nCouleur conditionnelle sur Dépréciation : rouge si < -30%.", why: "Les 4 KPI résument le projet en un coup d'oeil : combien de jeux, à quel prix moyen, quelle dépréciation, et combien de temps." },
  { id: "r30", ch: 7, title: "Courbe de dépréciation principale", text: "Graphique en courbes : MonthsSinceLaunch en axe, Prix Moyen en valeur. Ajoute un segment publisher pour filtrer.", type: "action", xp: 15, solution: "Graphique en courbes principal :\n- Axe X = PriceHistory[MonthsSinceLaunch] (filtré 0-36)\n- Valeur = [Prix Moyen]\n- Titre : 'Courbe de dépréciation — Prix moyen par ancienneté'\n\nSegment Games[publisher] en haut à droite (dropdown multi-select).\n\nAjoute un 2e Graphique en courbes avec Games[genre] en légende pour comparer les courbes de dépréciation par genre (les jeux de simulation se déprécient-ils plus vite que les arcade ?).", why: "C'est LE visuel signature du projet. Il montre visuellement la mécanique de dépréciation des jeux de course." },
  { id: "r31", ch: 7, title: "Nuage de points prix vs ventes", text: "Nuage de points : axe X = Prix Moyen, axe Y = Ventes Totales, Détails = Games[title]. Identifie les outliers.", type: "action", xp: 20, solution: "Nuage de points :\n- Axe X = [Prix Moyen]\n- Axe Y = SUM(GameSales[units_sold])\n- Détails = Games[title] (chaque point = un jeu)\n- Taille des bulles (optionnel) = SUM(GameSales[revenue_eur])\n\nAnalyse : les jeux en haut-gauche (prix bas, ventes élevées) sont les bonnes affaires. Les jeux en bas-droite (prix élevé, ventes faibles) sont potentiellement surévalués.\n\nTitre business : 'Positionnement prix vs volume de ventes'", why: "Le Nuage de points est idéal pour identifier les corrélations et les outliers. C'est un visuel avancé très apprécié en entretien." },
  { id: "r32", ch: 7, title: "Histogramme top publishers", text: "Histogramme : Top 10 publishers par CA. Couleurs différentes pour Ubisoft (highlight).", type: "action", xp: 15, solution: "Histogramme horizontal :\n- Axe Y = Games[publisher]\n- Valeur = [CA Total Racing]\n- Trié DESC par [CA Total Racing]\n- Filtre visuel : Top 10\n\nPour highlight Ubisoft : Format → Couleur des données → fx → Règles → Si publisher = 'Ubisoft' alors bleu foncé, sinon gris.\n\nTitre : 'Top 10 éditeurs par chiffre d\\'affaires'", why: "Le Histogramme top publishers positionne Ubisoft par rapport à la concurrence. Le highlight couleur attire l'attention sur ton employeur." },
  { id: "r33", ch: 7, title: "Scorecard dépréciation", text: "Tableau/Matrice : Publisher × Nb Jeux × Prix Moyen × Dépréciation % × Months to Half. MFC sur dépréciation.", type: "action", xp: 20, solution: "Matrice :\n- Lignes = Games[publisher]\n- Valeurs = [Nb Jeux], [Prix Moyen], [Depreciation %], [Months To Half Price]\n\nMFC :\n- Depreciation % : échelle couleurs inversée (vert = faible dépréciation, rouge = forte)\n- Months To Half : barres de données\n- Prix Moyen : pas de MFC (information brute)\n\nTri par [Nb Jeux] DESC pour les plus gros éditeurs en premier.\n\nTitre : 'Scorecard dépréciation par éditeur'", why: "Ce scorecard est le tableau de synthèse du projet. Il permet de comparer les stratégies de pricing des éditeurs en un coup d'oeil." },
  { id: "r34", ch: 7, title: "Navigation et publication Racing", text: "Ajoute navigation (boutons), signets (vue Synthèse / vue Détail), et publie le rapport Racing Games sur le Service.", type: "action", xp: 25, solution: "1. NAVIGATION : 2 boutons en haut de chaque page → 'Synthèse' (KPI + courbe) et 'Détail' (scorecard + scatter).\n\n2. SIGNETS : sur la page Synthèse, créer 'Vue Globale' (tous publishers) et 'Vue Ubisoft' (segment pré-filtré sur Ubisoft).\n\n3. THÈME : 3 couleurs — bleu Ubisoft (#0070E0), gris (#666), accent orange (#FF6B00). Segoe UI. Fond blanc.\n\n4. PUBLICATION : Ctrl+S → Accueil → Publier → Workspace 'Racing Games' → Publier.\n\n5. Vérifier dans le Service que les visuels fonctionnent.\n\nCe projet Racing Games est ton DEUXIÈME projet portfolio (après AdventureWorks). En entretien, tu montres AdventureWorks (formation) ET Racing Games (projet personnel) = double crédibilité.", why: "Le projet Racing Games montre ton initiative personnelle au-delà de la formation. C'est ce qui te différencie des autres candidats PL-300." }
];

