// QUESTIONS D'ENTRETIEN DATA ANALYST / POWER BI
// ═══════════════════════════════════════════════════════════
var INTERVIEW = [
  // ─── DAX (8 questions) ───
  { id: 1, category: "DAX", q: "Expliquez la différence entre une mesure et une colonne calculée.",
    ideal: "Une mesure est dynamique — elle se recalcule selon le contexte de filtre (segments, visuels). Une colonne calculée est statique — évaluée une seule fois au chargement. En pratique, 95% du temps on utilise des mesures. On utilise une colonne calculée uniquement pour des propriétés fixes par ligne (concaténation de noms, segmentation statique).",
    traps: ["Ne pas dire 'c est pareil'", "Ne pas confondre avec les colonnes Power Query"],
    whatTheyWant: "Compréhension du contexte d'évaluation et choix pragmatique" },
  { id: 2, category: "DAX", q: "Qu'est-ce que CALCULATE et pourquoi c'est la fonction la plus importante de DAX ?",
    ideal: "CALCULATE modifie le contexte de filtre puis évalue une expression. C'est la seule fonction qui permet de changer les filtres actifs. Sans CALCULATE, les mesures ne répondent qu'au contexte du visuel. Avec CALCULATE, on peut forcer un pays, supprimer des filtres avec ALL, activer des relations inactives avec USERELATIONSHIP.",
    traps: ["Ne pas dire 'CALCULATE calcule'", "Bien expliquer REMPLACE vs AJOUTE"],
    whatTheyWant: "Maîtrise du concept de contexte de filtre et de sa manipulation" },
  { id: 3, category: "DAX", q: "Quelle différence entre ALL et ALLSELECTED ? Quand utiliser l'un ou l'autre ?",
    ideal: "ALL supprime TOUS les filtres, y compris les segments et le RLS. ALLSELECTED supprime les filtres du visuel (axes, légendes) mais garde les filtres externes (segments, RLS, filtres de page). En pratique, ALLSELECTED est correct dans 90% des cas car il respecte la sécurité (RLS) et les choix de l'utilisateur (segments).",
    traps: ["Ne pas oublier l'impact sur le RLS", "Ne pas dire qu'ils sont identiques"],
    whatTheyWant: "Compréhension des implications de sécurité et usage pragmatique" },
  { id: 4, category: "DAX", q: "Expliquez la différence entre SUM et SUMX. Quand utiliser SUMX ?",
    ideal: "SUM agrège une seule colonne existante. SUMX est un itérateur qui parcourt chaque ligne, évalue une expression multi-colonnes, puis somme les résultats. On utilise SUMX quand le calcul combine plusieurs colonnes de la même ligne, par exemple la marge (prix - coût) par transaction. SUM est plus performant pour les cas simples.",
    traps: ["Ne pas dire 'SUMX est toujours mieux'", "Mentionner l'aspect performance"],
    whatTheyWant: "Savoir quand un itérateur est nécessaire et comprendre le contexte de ligne" },
  { id: 5, category: "DAX", q: "À quoi servent VAR et RETURN en DAX ?",
    ideal: "VAR stocke le résultat d'une sous-expression, évalué une seule fois. RETURN utilise ces variables. Trois avantages : lisibilité (code structuré au lieu d'une formule sur une ligne), performance (pas de recalcul), debug (on peut changer RETURN pour inspecter une VAR intermédiaire). Point important : les VAR sont évaluées dans le contexte au moment de leur déclaration.",
    traps: ["Mentionner le contexte d'évaluation des VAR", "Ne pas confondre avec des variables mutables"],
    whatTheyWant: "Code DAX professionnel et maintenable" },
  { id: 6, category: "DAX", q: "Pourquoi utiliser DIVIDE au lieu de l'opérateur / ?",
    ideal: "DIVIDE(a, b, alt) protège contre la division par zéro. Quand un segment filtre toutes les données, le dénominateur peut être 0 ou BLANK. L'opérateur / génère #DIV/0, DIVIDE retourne proprement la valeur alternative (souvent 0 ou BLANK). C'est une règle absolue en DAX professionnel.",
    traps: ["Ne pas dire 'c est juste du cosmétique'"],
    whatTheyWant: "Robustesse du code DAX en production" },
  { id: 7, category: "DAX", q: "Qu'est-ce qu'un itérateur en DAX ? Donnez des exemples.",
    ideal: "Un itérateur parcourt chaque ligne d'une table et évalue une expression dans un contexte de ligne. Exemples : SUMX, AVERAGEX, MINX, MAXX, COUNTX, RANKX, FILTER. Ils prennent tous une table en 1er argument et une expression en 2e. FILTER est un itérateur qui retourne une table filtrée. RANKX crée un classement.",
    traps: ["Ne pas oublier FILTER qui est aussi un itérateur", "Mentionner le contexte de ligne"],
    whatTheyWant: "Compréhension du contexte de ligne vs contexte de filtre" },
  { id: 8, category: "DAX", q: "Qu'est-ce que la context transition en DAX ?",
    ideal: "Quand CALCULATE est appelé dans un itérateur ou une colonne calculée, il convertit le contexte de ligne en contexte de filtre. Chaque colonne de la ligne courante devient un filtre. C'est ce qui permet aux mesures de fonctionner correctement dans les colonnes calculées et les itérateurs. Sans CALCULATE, il n'y a pas de transition.",
    traps: ["C'est un concept avancé — montrer qu'on le comprend est un gros plus"],
    whatTheyWant: "Niveau avancé de compréhension DAX" },

  // ─── Modélisation (6 questions) ───
  { id: 9, category: "Modélisation", q: "Qu'est-ce qu'un schéma en étoile et pourquoi est-il recommandé pour Power BI ?",
    ideal: "Table de faits (transactions) au centre avec les FK et les mesures. Tables de dimensions (contexte) autour avec les PK et les attributs descriptifs. Les dimensions filtrent les faits via des relations 1:N. L'étoile est optimale pour Power BI car le moteur VertiPaq compresse mieux les colonnes avec peu de valeurs distinctes (dimensions), et les filtres se propagent naturellement de la dimension vers les faits.",
    traps: ["Mentionner la performance VertiPaq", "Ne pas confondre avec le flocon de neige"],
    whatTheyWant: "Compréhension architecturale, pas juste un dessin" },
  { id: 10, category: "Modélisation", q: "Comment gérez-vous une relation N:N entre deux tables ?",
    ideal: "Créer une table pont (bridge table) contenant les combinaisons uniques des deux clés. On obtient deux relations 1:N au lieu d'une N:N. Exemple : Étudiants ↔ Cours → table Inscriptions(ÉtudiantID, CoursID). Ne jamais utiliser la direction Both comme solution — cela crée des ambiguïtés de chemin et des résultats imprévisibles.",
    traps: ["Ne JAMAIS proposer Both comme solution", "Mentionner que TREATAS est une alternative légère"],
    whatTheyWant: "Solution propre et connaissance des anti-patterns" },
  { id: 11, category: "Modélisation", q: "Pourquoi créer une table de dates séparée ? Quels sont les prérequis ?",
    ideal: "Les fonctions Time Intelligence (TOTALYTD, SAMEPERIODLASTYEAR, DATEADD) nécessitent une table de dates. Trois prérequis absolus : 1) Continue — chaque jour calendaire sans trous. 2) Marquée comme table de dates. 3) Relation active avec la table de faits. Ne jamais utiliser la colonne date des faits directement : elle a des trous (week-ends) et des doublons.",
    traps: ["Citer les 3 prérequis sans hésiter", "Expliquer pourquoi les trous sont problématiques"],
    whatTheyWant: "Rigueur technique et compréhension des prérequis Time Intelligence" },
  { id: 12, category: "Modélisation", q: "Expliquez la direction de filtre Single vs Both. Pourquoi éviter Both ?",
    ideal: "Single (→) signifie que les filtres se propagent de la dimension vers les faits. C'est le sens naturel : on filtre par pays (dimension) pour voir les ventes (faits). Both (↔) ajoute le sens inverse : les faits filtrent aussi les dimensions. Risques : ambiguïtés de chemin quand plusieurs chemins existent entre 2 tables, performance dégradée, résultats imprévisibles. Microsoft recommande Single sauf cas exceptionnel.",
    traps: ["Ne pas dire 'j utilise Both par défaut'", "Donner un exemple d'ambiguïté"],
    whatTheyWant: "Connaissance des bonnes pratiques Microsoft" },
  { id: 13, category: "Modélisation", q: "Qu'est-ce que le RLS et comment le mettre en place ?",
    ideal: "Row Level Security filtre les données selon l'utilisateur connecté. Deux étapes obligatoires : 1) Créer les rôles dans Desktop (Modélisation → Gérer les rôles → filtre DAX). 2) Assigner les utilisateurs aux rôles dans le Service (Dataset → Sécurité). Le RLS dynamique utilise USERNAME() ou USERPRINCIPALNAME() avec une table de mapping. Attention : ALL() supprime le RLS — utiliser ALLSELECTED à la place.",
    traps: ["Insister sur les 2 étapes (créer ≠ appliquer)", "Mentionner le piège ALL vs ALLSELECTED"],
    whatTheyWant: "Maîtrise de la sécurité de bout en bout" },
  { id: 14, category: "Modélisation", q: "Comment utilisez-vous USERELATIONSHIP et dans quel cas ?",
    ideal: "Quand une table de faits a 2 colonnes de date (ex: date commande et date livraison) liées à la même table de dates, une seule relation peut être active. USERELATIONSHIP active ponctuellement la relation inactive dans CALCULATE. Exemple : CA Livraison = CALCULATE([CA Total], USERELATIONSHIP(Orders[shipdate], DateTable[Date])). Cela permet d'analyser les mêmes données sous 2 angles temporels.",
    traps: ["Donner un exemple concret", "Expliquer pourquoi une seule relation active"],
    whatTheyWant: "Cas d'usage concret des relations inactives" },

  // ─── Power Query (5 questions) ───
  { id: 15, category: "Power Query", q: "Quelle est la différence entre Merge et Append dans Power Query ?",
    ideal: "Merge = JOIN en SQL, ajoute des COLONNES d'une autre table via une clé commune. Après un Merge, il faut Expand pour voir les valeurs. Append = UNION en SQL, empile des LIGNES de même structure. Erreur classique : confondre les deux. Merge quand tu veux enrichir (ajouter le nom du produit). Append quand tu veux combiner (fichiers mensuels).",
    traps: ["Mentionner l'Expand obligatoire après le Merge", "Donner un cas d'usage pour chacun"],
    whatTheyWant: "Clarté conceptuelle et cas d'usage pratiques" },
  { id: 16, category: "Power Query", q: "Pourquoi faire le nettoyage dans Power Query plutôt qu'en DAX ?",
    ideal: "Le nettoyage dans PQ est exécuté une seule fois au chargement. En DAX, les transformations sont recalculées à chaque interaction. PQ réduit la taille du modèle en mémoire (colonnes supprimées, lignes filtrées). De plus, PQ bénéficie du Query Folding qui pousse les transformations vers la source (SQL). Règle fondamentale : PQ = nettoyage et types, DAX = calculs analytiques.",
    traps: ["Mentionner le Query Folding", "Donner la règle PQ vs DAX"],
    whatTheyWant: "Compréhension de l'architecture et de la performance" },
  { id: 17, category: "Power Query", q: "Qu'est-ce que le Query Folding et pourquoi est-ce important ?",
    ideal: "Le Query Folding signifie que Power Query traduit les transformations en requêtes natives (SQL) exécutées directement sur la source. Le serveur fait le travail au lieu de PBI. C'est beaucoup plus rapide pour les grands volumes. On vérifie si le folding est actif en faisant clic droit sur une étape → Afficher la requête native. Certaines étapes cassent le folding (colonnes personnalisées complexes, merge entre sources différentes).",
    traps: ["Expliquer comment vérifier le folding", "Citer ce qui le casse"],
    whatTheyWant: "Optimisation des performances au niveau données" },
  { id: 18, category: "Power Query", q: "Quelle est la structure du langage M ?",
    ideal: "Structure let / in. let contient des variables séquentielles, chaque variable correspond à une étape appliquée dans l'interface. in retourne la dernière variable (le résultat). Les variables référencent les précédentes, formant un pipeline. Pour l'examen PL-300, il faut savoir lire le code M, pas forcément l'écrire from scratch.",
    traps: ["Ne pas prétendre maîtriser M à 100% si ce n'est pas le cas", "Montrer qu'on sait le lire"],
    whatTheyWant: "Capacité à lire et comprendre le code M" },
  { id: 19, category: "Power Query", q: "Comment gérez-vous les paramètres de requête dans Power Query ?",
    ideal: "Les paramètres PQ rendent les requêtes flexibles : chemin de fichier, nom de serveur, seuil de filtre. On les crée via Gérer les paramètres → Nouveau. Ils sont réutilisables dans plusieurs requêtes. En production, on les utilise pour basculer entre les environnements (dev/prod) sans modifier le code M. Le PL-300 teste la connaissance des paramètres.",
    traps: ["Donner un cas d'usage concret (changement d'environnement)"],
    whatTheyWant: "Pratique professionnelle et industrialisation" },

  // ─── Service & Gouvernance (5 questions) ───
  { id: 20, category: "Service", q: "Quelles sont les différences entre les licences Free, Pro et PPU ?",
    ideal: "Free : consultation dans Mon espace uniquement, pas de partage, pas de refresh planifié. Pro (~10€/mois) : workspaces partagés, apps, 8 refreshs/jour, RLS, alertes. PPU (~20€/mois) : tout Pro + 48 refreshs/jour, dataflows, Deployment Pipelines, fonctionnalités Premium sans capacité dédiée. Le choix dépend du volume de refresh et des fonctionnalités nécessaires.",
    traps: ["Connaître les limites de refresh par licence", "Mentionner que Premium capacité est différent de PPU"],
    whatTheyWant: "Connaissance de l'écosystème de licences" },
  { id: 21, category: "Service", q: "Comment configurez-vous le refresh planifié et quels sont les prérequis ?",
    ideal: "Dans le Service : Dataset → Paramètres → Actualisation planifiée → Activer → Définir fréquence et heure. Prérequis : credentials de la source configurées dans le Service. Si source on-premises : Gateway obligatoire. Stratégie : planifier aux heures creuses (6h du matin). Pour les grands volumes : Incremental Refresh pour ne recharger que les nouvelles données.",
    traps: ["Mentionner le Gateway pour les sources on-premises", "Évoquer l'Incremental Refresh"],
    whatTheyWant: "Capacité à mettre en production un rapport" },
  { id: 22, category: "Service", q: "Quels sont les rôles de workspace et leurs permissions ?",
    ideal: "Du plus au moins de droits : Admin (tout, supprimer workspace, gérer accès), Membre (publier, éditer, gérer datasets/refresh), Contributeur (publier et éditer rapports), Lecteur (consulter uniquement). Point important : Admin et Membre ne sont PAS soumis au RLS — ils voient toutes les données. Seuls Lecteur et Contributeur sont filtrés par RLS.",
    traps: ["Mentionner que Admin/Membre échappent au RLS"],
    whatTheyWant: "Gouvernance et sécurité" },
  { id: 23, category: "Service", q: "Quelle est la différence entre 'Publier sur le web' et 'Incorporer dans SharePoint' ?",
    ideal: "'Publier sur le web' génère un lien public accessible à QUICONQUE — zéro authentification, zéro sécurité. Ne JAMAIS utiliser pour des données d'entreprise. 'Incorporer dans SharePoint' intègre le rapport dans l'intranet avec authentification Azure AD. C'est la méthode sécurisée. Pour des applications tierces : Power BI Embedded avec embed tokens.",
    traps: ["Insister fortement sur le danger de 'Publier sur le web'"],
    whatTheyWant: "Conscience de la sécurité des données" },
  { id: 24, category: "Service", q: "Comment gérez-vous le versioning d'un rapport Power BI ?",
    ideal: "Le .pbix est un fichier binaire difficilement versionnable avec Git classique. Solution moderne : Power BI Projects (.pbip) qui décompose le rapport en fichiers texte (JSON, TMDL) versionnables avec Git. Alternative : SharePoint avec versioning. Pour le déploiement : Deployment Pipelines (Dev → Test → Prod) dans le Service. En équipe, un workspace de développement séparé est recommandé.",
    traps: ["Mentionner .pbip comme solution moderne", "Évoquer les Deployment Pipelines"],
    whatTheyWant: "Maturité professionnelle et travail en équipe" },

  // ─── Méthodologie (3 questions) ───
  { id: 25, category: "Méthodologie", q: "Comment abordez-vous un nouveau projet Power BI de A à Z ?",
    ideal: "7 phases dans l'ordre : 1) Comprendre le besoin business (quelles questions, quels KPI). 2) Identifier les sources et se connecter. 3) Nettoyer dans Power Query (types, colonnes, filtres). 4) Modéliser en étoile (relations 1:N, table de dates). 5) Créer les mesures DAX (KPI de base puis avancées). 6) Construire les visuels (max 6-8 par page, MFC, extraction). 7) Déployer (publier, refresh, RLS, application). L'erreur classique est de commencer par les visuels sans avoir un modèle propre.",
    traps: ["Insister sur l'ordre des phases", "Mentionner que 80% du temps est sur les phases 2-4"],
    whatTheyWant: "Méthodologie structurée et expérience pratique" },
  { id: 26, category: "Méthodologie", q: "Comment optimisez-vous un rapport Power BI lent ?",
    ideal: "Diagnostic avec Performance Analyzer (Affichage → Analyseur de performances) pour identifier les visuels lents. Ensuite : 1) Réduire le nombre de colonnes chargées dans PQ. 2) Utiliser Import au lieu de DirectQuery. 3) Simplifier les mesures DAX (remplacer FILTER par des filtres directs quand possible). 4) Réduire le nombre de visuels par page (max 6-8). 5) Utiliser des agrégations ou des tables résumées. 6) DAX Studio pour analyser les requêtes lentes.",
    traps: ["Mentionner Performance Analyzer comme premier réflexe", "Citer des actions concrètes"],
    whatTheyWant: "Capacité à diagnostiquer et résoudre les problèmes de performance" },
  { id: 27, category: "Méthodologie", q: "Import vs DirectQuery vs Composite : comment choisir ?",
    ideal: "Import : données copiées en mémoire, ultra rapide, DAX complet, mais données pas en temps réel (refresh nécessaire). Idéal pour < 1 Go. DirectQuery : requêtes en direct, données toujours à jour, mais plus lent et DAX limité. Pour les grands volumes ou le temps réel. Composite : mix des deux — tables volumineuses en Import, tables critiques en DirectQuery. Le mode Composite offre le meilleur compromis performance/fraîcheur.",
    traps: ["Ne pas dire 'Import toujours'", "Mentionner le mode Composite"],
    whatTheyWant: "Capacité à faire des choix architecturaux adaptés" },

  // ─── Soft Skills (3 questions) ───
  { id: 28, category: "Soft Skills", q: "Comment expliquez-vous un KPI complexe à un interlocuteur non technique ?",
    ideal: "J'utilise des analogies business. Par exemple, le YoY% : 'C est comme comparer vos ventes de ce mois avec le même mois l an dernier. Si on fait +15%, on a 15% de plus que la même période.' Je montre toujours le visuel correspondant et j'explique ce que le chiffre signifie pour le business, pas comment il est calculé. Les tableaux de bord doivent raconter une histoire, pas afficher des formules.",
    traps: ["Ne pas utiliser de jargon technique", "Montrer qu'on adapte son discours"],
    whatTheyWant: "Communication et vulgarisation" },
  { id: 29, category: "Soft Skills", q: "Comment gérez-vous un changement de spécifications en cours de projet ?",
    ideal: "D'abord, je valide le nouveau besoin avec le demandeur pour comprendre l'impact. Ensuite, j'évalue la charge technique (nouveau KPI = quelques heures, nouveau modèle = plusieurs jours). Je communique un délai réaliste. Si le rapport est déjà en production, je travaille dans un workspace de développement et je déploie via Deployment Pipeline. L'avantage de Power BI : les mesures DAX sont modulaires, ajouter un KPI est souvent rapide si le modèle est bien construit.",
    traps: ["Montrer de la flexibilité mais aussi de la rigueur", "Mentionner l'impact sur le planning"],
    whatTheyWant: "Gestion de projet et communication" },
  { id: 30, category: "Soft Skills", q: "Décrivez votre workflow quotidien type en tant que Data Analyst.",
    ideal: "Matin : vérifier que les refreshs planifiés se sont bien passés (historique d'actualisation dans le Service). Traiter les demandes ad hoc des équipes métier (nouveau KPI, filtre, visuel). Après-midi : développement sur les projets en cours (nouvelles mesures, nouvelles pages, nettoyage PQ). Documentation des mesures et des sources. Revue des performances des rapports existants. Veille technique (nouvelles fonctionnalités PBI, DAX patterns). Hebdomairement : review avec les équipes métier pour valider les rapports et recueillir les retours.",
    traps: ["Montrer une routine structurée", "Mentionner la documentation et la veille"],
    whatTheyWant: "Organisation, autonomie et conscience professionnelle" }
];

